from itertools import permutations


class Solution:
    def minimumMoves(self, grid):
        cells = [(r, c) for r in range(3) for c in range(3)]
        sources = []
        for r in range(3):
            for c in range(3):
                sources.extend([(r, c)] * grid[r][c])
        best = None
        for perm in permutations(cells):
            total = 0
            for i in range(9):
                total += abs(sources[i][0] - perm[i][0]) + abs(sources[i][1] - perm[i][1])
            if best is None or total < best:
                best = total
        return best

