class Solution:
    def minimumMoves(self, grid: List[List[int]]) -> int:
        sources = []
        for r in range(3):
            for c in range(3):
                sources.extend([(r, c)] * grid[r][c])
        targets = [(r, c) for r in range(3) for c in range(3)]
        n = 9
        inf = float('inf')
        dp = [inf] * (1 << n)
        dp[0] = 0
        for mask in range(1 << n):
            if dp[mask] == inf:
                continue
            i = bin(mask).count('1')
            if i >= n:
                continue
            for j in range(n):
                if mask & (1 << j):
                    continue
                cost = abs(sources[i][0] - targets[j][0]) + abs(sources[i][1] - targets[j][1])
                nmask = mask | (1 << j)
                if dp[mask] + cost < dp[nmask]:
                    dp[nmask] = dp[mask] + cost
        return dp[(1 << n) - 1]

