var minimumMoves = function(grid) {
    const sources = [];
    for (let r = 0; r < 3; r++) {
        for (let c = 0; c < 3; c++) {
            for (let k = 0; k < grid[r][c]; k++) sources.push([r, c]);
        }
    }
    const targets = [];
    for (let r = 0; r < 3; r++) for (let c = 0; c < 3; c++) targets.push([r, c]);
    const n = 9;
    const size = 1 << n;
    const dp = new Array(size).fill(Infinity);
    dp[0] = 0;
    const popcount = (x) => { let c = 0; while (x) { c += x & 1; x >>= 1; } return c; };
    for (let mask = 0; mask < size; mask++) {
        if (dp[mask] === Infinity) continue;
        const i = popcount(mask);
        if (i >= n) continue;
        for (let j = 0; j < n; j++) {
            if (mask & (1 << j)) continue;
            const cost = Math.abs(sources[i][0] - targets[j][0]) + Math.abs(sources[i][1] - targets[j][1]);
            const nmask = mask | (1 << j);
            if (dp[mask] + cost < dp[nmask]) dp[nmask] = dp[mask] + cost;
        }
    }
    return dp[size - 1];
};
